/**
 * @brief   Registers a service availability callback with the middleware.
 * @details In a real integration this calls the generated FindService API.
 *          Here the callback is stored and invoked synchronously with a
 *          simulated available handle to satisfy the pseudocode contract.
 * @param[in] instanceId  Resolved service instance identifier.
 * @param[in] callback    Availability callback accepting a vector of ServiceHandle.
 */
static void RegisterServiceAvailabilityCallback(
    const ServiceInstanceId&                                    instanceId,
    std::function<void(std::vector<ServiceHandle>, bool)>       callback) noexcept
{
    if (!instanceId.valid) {
        return;
    }
    // Simulate immediate availability notification with a matching handle.
    ServiceHandle handle;
    handle.instanceId.id    = instanceId.id;
    handle.instanceId.valid = instanceId.valid;
    handle.valid            = true;
    std::vector<ServiceHandle> handles{handle};
    callback(handles, true);
}

