/**
 * @brief   Creates a service consumer proxy for the given handle.
 * @param[in] handle  Service handle returned by the availability callback.
 * @return  ServiceProxy — bound when creation succeeds.
 */
static ServiceProxy CreateServiceProxy(const ServiceHandle& handle) noexcept
{
    ServiceProxy proxy;
    proxy.handle = handle;
    proxy.bound  = handle.valid;
    proxy.valid  = handle.valid;
    return proxy;
}

/**
 * @brief   Resets (invalidates) a service consumer proxy.
 * @param[in,out] proxy  Proxy to invalidate.
 */
static void ResetServiceProxy(ServiceProxy& proxy) noexcept
{
    proxy.bound               = false;
    proxy.valid               = false;
    proxy.handle.valid        = false;
    proxy.handle.instanceId.id    = 0U;
    proxy.handle.instanceId.valid = false;
}

/**
 * @brief   Destroys a service consumer proxy (alias for reset in this abstraction).
 * @param[in,out] proxy  Proxy to destroy.
 */
static void DestroyServiceProxy(ServiceProxy& proxy) noexcept
{
    ResetServiceProxy(proxy);
}

