/**
 * @brief   Locates the DAQ SOME/IP continual data service for steady-state data transmission.
 * @details Resolves the CORE_DAQ_continual_Service instance identifier. If valid, registers
 *          an availability callback (OnContinualServiceAvailabilityChanged). The callback
 *          acquires sendBufferMutex_null and sets daqCommunicationEstablished_ to true when
 *          the service is available, or false when it becomes unavailable. The function
 *          returns immediately after callback registration; all subsequent state updates
 *          are driven asynchronously by the registered callback.
 * @pre     ProbeComm has been constructed with a valid variant.
 * @post    Internal service handle for DAQ continual is populated on success.
 *          daqCommunicationEstablished_ is set to true when service is found.
 * @throws  None.
 * @note    Called by: ProbeApp. Call condition: Startup.
 * @warning Data suppression (SuppressDataBeforeDaqEstablished) remains active until this
 *          call completes successfully.
 * @requirements SWR-REQ-01-04-001;SWR-REQ-01-06-003;SWR-REQ-03-16-002
 * @rationale Separate discovery per service allows independent retry and fault isolation.
 * @see     SuppressDataBeforeDaqEstablished, SendContinualShortDataCyclic100ms
 */
void ProbeComm::FindServiceDaqContinual() noexcept
{
    // Resolve the service instance identifier for CORE_DAQ_continual_Service.
    const ServiceInstanceId continualServiceInstanceId{ResolveContinualServiceInstanceId()};

    if (!continualServiceInstanceId.valid) {
        // Log error and return; retry will be attempted on next startup cycle by execution management.
        LogError("CORE_DAQ_continual_Service instance ID resolution failed");
        return;
    }

    // Register availability callback for CORE_DAQ_continual_Service.
    // The lambda captures 'this' to update daqCommunicationEstablished_ under mutex protection.
    RegisterServiceAvailabilityCallback(
        continualServiceInstanceId,
        [this](std::vector<ServiceHandle> /*handles*/, bool isAvailable) noexcept {
            // CALLBACK OnContinualServiceAvailabilityChanged
            if (isAvailable) {
                // Service found: update internal communication flag.
                std::lock_guard<std::mutex> lock{sendBufferMutex_null};
                daqCommunicationEstablished_ = true;
            } else {
                // Service lost: suppress transmission until rediscovery.
                std::lock_guard<std::mutex> lock{sendBufferMutex_null};
                daqCommunicationEstablished_ = false;
            }
        });

    // Asynchronous discovery initiated; function returns after callback registration.
    // daqCommunicationEstablished_ will be updated by the callback when service is found.
}

bool ProbeComm::InitiateSomeIpDiscovery() noexcept
{
    FindServiceDaqContinual();
    return daqCommunicationEstablished_;
}

