/**
 * @brief   Locates the ZAT trigger service for receiving event triggers at 100 ms periodic rate.
 * @details Resolves the ZAT_hdfProbeBusOut_Service instance identifier. If valid, registers
 *          an availability callback (OnZatServiceAvailabilityChanged). On service appearance
 *          the callback creates a proxy, subscribes to the trigger event, and registers
 *          HandleAdasAcoreTriggerEvt. The trigger event handler validates the upload request
 *          flag, enforces overlap and per-category limits, clamps log times, and updates all
 *          accepted trigger state fields.
 * @pre     ProbeComm has been constructed with a valid variant.
 * @post    ZAT trigger event subscription is active on success.
 *          zatTriggerReceived_ is set to true when service is available.
 * @throws  None.
 * @note    Called by: ProbeApp. Call condition: Startup.
 * @requirements SWR-REQ-03-02-001;SWR-REQ-03-003
 * @rationale ZAT trigger drives the core event detection pipeline.
 * @see     HandleAdasAcoreTriggerEvt
 */
void ProbeComm::FindServiceZatTrigger() noexcept
{
    // Resolve service instance ID for ZAT_hdfProbeBusOut_Service.
    const ServiceInstanceId zatServiceInstanceId{ResolveZatServiceInstanceId()};

    if (!zatServiceInstanceId.valid) {
        LogError("ZAT_hdfProbeBusOut_Service instance ID resolution failed");
        return;
    }

    // Register service availability callback.
    RegisterServiceAvailabilityCallback(
        zatServiceInstanceId,
        [this](std::vector<ServiceHandle> availableHandles, bool isAvailable) noexcept {
            // CALLBACK OnZatServiceAvailabilityChanged
            if (isAvailable && !availableHandles.empty()) {
                // Create proxy and subscribe to trigger event.
                ServiceProxy zatProxy{CreateServiceProxy(availableHandles[0])};
                if (zatProxy.bound) {
                    SubscribeToTriggerEvent(zatProxy);
                    RegisterEventHandler("HandleAdasAcoreTriggerEvt");
                    zatTriggerReceived_ = true;
                }
            } else {
                // Service lost: disable trigger reception.
                zatTriggerReceived_ = false;
                // Proxy is a local variable; destruction is implicit (RAII).
                // DestroyServiceProxy is called conceptually here.
                ServiceProxy emptyProxy;
                DestroyServiceProxy(emptyProxy);
            }
        });

    // Asynchronous discovery initiated; function returns after callback registration.
}

