/**
 * @brief   Locates the CameraHost image service for receiving camera images.
 * @details Initializes cameraAnswerBackReceived_ to false, then registers a service
 *          availability callback for CameraHost_IMG_Service. On service appearance the
 *          callback creates a proxy, resets cameraAnswerBackReceived_, subscribes to the
 *          answer back and picture events, and registers HandleCam2ProbeAnswerBackEvt and
 *          HandleCam2ProbePictureEvt. On disappearance the proxy is reset and
 *          cameraAnswerBackReceived_ is set to false.
 * @pre     ProbeComm has been constructed with a valid variant.
 * @post    CameraHost image event subscriptions are active on success.
 * @throws  None.
 * @note    Called by: ProbeApp. Call condition: Startup.
 * @requirements SWR-REQ-03-06-002;SWR-REQ-03-06-006
 * @see     HandleCam2ProbePictureEvt, HandleCam2ProbeAnswerBackEvt
 */
void ProbeComm::FindServiceCameraImg() noexcept
{
    // Step 1: Log entry into camera image service discovery.
    LogInfo("Starting FindService for CameraHost_IMG_Service");

    // Step 2: Initialize cameraAnswerBackReceived to false.
    cameraAnswerBackReceived_ = false;

    // Resolve the CameraHost_IMG_Service instance identifier.
    // Using a dedicated constant for CameraHost IMG service instance.
    ServiceInstanceId cameraImgInstanceId;
    cameraImgInstanceId.id    = 0x0030U;
    cameraImgInstanceId.valid = true;

    // Step 3: Register service availability callback with middleware.
    RegisterServiceAvailabilityCallback(
        cameraImgInstanceId,
        [this, cameraImgInstanceId](std::vector<ServiceHandle> availableHandles,
                                    bool /*isAvailable*/) noexcept {
            // ON EVENT OnCameraImgServiceAvailability(availableHandles)
            if (!availableHandles.empty()) {
                // Step 4a: Iterate through available handles.
                for (const ServiceHandle& handle : availableHandles) {
                    if (handle.instanceId.id == cameraImgInstanceId.id) {
                        // Step 4b: Create service consumer proxy.
                        ServiceProxy proxy{CreateServiceProxy(handle)};
                        if (proxy.bound) {
                            // Step 4c: Initialize cameraAnswerBackReceived flag.
                            {
                                std::lock_guard<std::mutex> lock{cameraMutex_null};
                                cameraAnswerBackReceived_ = false;
                            }
                            // Step 4d: Subscribe to camera answer back event.
                            SubscribeToCameraAnswerBackEvent(proxy);
                            // Step 4e: Register handler for answer back event.
                            RegisterEventHandler("HandleCam2ProbeAnswerBackEvt");
                            // Step 4f: Subscribe to camera picture event.
                            SubscribeToCameraPictureEvent(proxy);
                            // Step 4g: Register handler for picture event.
                            RegisterEventHandler("HandleCam2ProbePictureEvt");
                            // Step 4h: Log successful binding.
                            LogInfo("CameraHost_IMG_Service proxy bound; handlers registered");
                        }
                        break;
                    }
                }
            } else {
                // Step 4i: Service disappeared - reset state.
                ServiceProxy emptyProxy;
                ResetServiceProxy(emptyProxy);
                {
                    std::lock_guard<std::mutex> lock{cameraMutex_null};
                    cameraAnswerBackReceived_ = false;
                }
                LogInfo("CameraHost_IMG_Service unavailable; proxy reset");
            }
        });

    // Step 5: Return; middleware manages retry independently.
}

