/**
 * @brief   Resolves the instance identifier for TSR2HDF_Service.
 * @details Returns a valid ServiceInstanceId for the TSR ACore HDF service.
 * @return  ServiceInstanceId — resolved instance identifier.
 */
ServiceInstanceId ResolveTsr2HdfInstanceId() noexcept
{
    return ServiceInstanceId{0x0009U};
}

/**
 * @brief   Resolves the instance identifier for hdfAp2CpBusOut_Service.
 * @details Returns a valid ServiceInstanceId for the HDF AP-to-CP bus output service.
 * @return  ServiceInstanceId — resolved instance identifier.
 */
ServiceInstanceId ResolveHdfAp2CpBusOutInstanceId() noexcept
{
    return ServiceInstanceId{0x000AU};
}

/**
 * @brief   Resolves the instance identifier for hdfCp2ApBusOut_Service.
 * @details Returns a valid ServiceInstanceId for the HDF CP-to-AP bus output service.
 * @return  ServiceInstanceId — resolved instance identifier.
 */
ServiceInstanceId ResolveHdfCp2ApBusOutInstanceId() noexcept
{
    return ServiceInstanceId{0x000BU};
}

/**
 * @brief   Resolves the service instance identifier for a named service.
 * @details Generic resolver used by SDMAP and service-offer paths.
 * @param[in] serviceName  Human-readable service name token.
 * @return  ServiceInstanceId — resolved instance identifier; id==0 on failure.
 */
ServiceInstanceId ResolveServiceInstanceId(const std::string& serviceName) noexcept
{
    if (serviceName == "SDMAP_Service")          { return ServiceInstanceId{0x000CU}; }
    if (serviceName == "probeEventStt_Service")  { return ServiceInstanceId{0x000DU}; }
    if (serviceName == "PROBE_TRG_Service")      { return ServiceInstanceId{0x000EU}; }
    return ServiceInstanceId{0U};
}

/**
 * @brief   Registers a service availability callback with the middleware.
 * @details The callback is invoked asynchronously when the service becomes available.
 * @param[in] serviceName   Human-readable service name token.
 * @param[in] instanceId    Instance identifier to monitor.
 * @param[in] callback      Callable invoked with a vector of discovered handles.
 */
void RegisterServiceAvailabilityCallback(
    const std::string& serviceName,
    const ServiceInstanceId& instanceId,
    std::function<void(std::vector<ServiceHandle>)> callback) noexcept
{
    (void)serviceName;
    (void)instanceId;
    (void)callback;
}

/**
 * @brief   Initiates non-blocking service discovery for the specified service.
 * @details Returns true when discovery was successfully initiated.
 * @param[in] serviceName  Human-readable service name token.
 * @param[in] instanceId   Instance identifier to discover.
 * @return  bool — true on success, false on failure.
 */
bool StartFindService(const std::string& serviceName,
                      const ServiceInstanceId& instanceId) noexcept
{
    (void)serviceName;
    (void)instanceId;
    return true;
}

/**
 * @brief   Creates a service proxy for the discovered service handle.
 * @details Returns a valid ServiceProxy when creation succeeds.
 * @param[in] serviceName     Human-readable service name token.
 * @param[in] selectedHandle  Handle of the discovered service instance.
 * @return  ServiceProxy — proxy object; valid==false on failure.
 */
ServiceProxy CreateServiceProxy(const std::string& serviceName,
                                 const ServiceHandle& selectedHandle) noexcept
{
    (void)serviceName;
    ServiceProxy proxy;
    proxy.handle = selectedHandle;
    proxy.valid  = selectedHandle.valid;
    proxy.bound  = selectedHandle.valid;
    return proxy;
}

/**
 * @brief   Creates a service skeleton for the specified service and instance.
 * @details Returns a valid ServiceSkeleton when creation succeeds.
 * @param[in] serviceName  Human-readable service name token.
 * @param[in] instanceId   Instance identifier for the skeleton.
 * @return  ServiceSkeleton — skeleton object; valid==false on failure.
 */
ServiceSkeleton CreateServiceSkeleton(const std::string& serviceName,
                                       const ServiceInstanceId& instanceId) noexcept
{
    (void)serviceName;
    (void)instanceId;
    ServiceSkeleton skeleton;
    skeleton.valid = true;
    return skeleton;
}

/**
 * @brief   Returns the configured past data retention limit in seconds.
 * @details Default value is 10 seconds per design specification.
 * @return  uint32_t — retention limit in seconds.
 */
uint32_t GetConfiguredRetentionLimit() noexcept
{
    return 10U;
}

// -----------------------------------------------------------------------
// Payload field extraction helpers
// -----------------------------------------------------------------------

/**
 * @brief   Extracts the data upload request flag from the raw trigger payload.
 * @details Reads byte at offset 0 of the payload. Returns 0 on undersized input.
 * @param[in] triggerData  Raw ZAT trigger payload bytes.
 * @return  uint8_t — extracted flag value.
 */
uint8_t ExtractDataUploadRequestFlag(const std::vector<uint8_t>& triggerData) noexcept
{
    if (triggerData.empty()) { return 0U; }
    return triggerData[0U];
}

/**
 * @brief   Extracts the data transmission number from the raw trigger payload.
 * @details Reads byte at offset 1 of the payload. Returns 0 on undersized input.
 * @param[in] triggerData  Raw ZAT trigger payload bytes.
 * @return  uint8_t — extracted transmission number.
 */
uint8_t ExtractDataTransmissionNum(const std::vector<uint8_t>& triggerData) noexcept
{
    if (triggerData.size() < 2U) { return 0U; }
    return triggerData[1U];
}

/**
 * @brief   Extracts the category identifier (4 bytes, little-endian) from the raw trigger payload.
 * @details Reads bytes at offsets 2–5 of the payload. Returns 0 on undersized input.
 * @param[in] triggerData  Raw ZAT trigger payload bytes.
 * @return  uint32_t — extracted category identifier.
 */
uint32_t ExtractCategoryIdentifier(const std::vector<uint8_t>& triggerData) noexcept
{
    if (triggerData.size() < 6U) { return 0U; }
    const uint32_t b0{static_cast<uint32_t>(triggerData[2U])};
    const uint32_t b1{static_cast<uint32_t>(triggerData[3U]) << 8U};
    const uint32_t b2{static_cast<uint32_t>(triggerData[4U]) << 16U};
    const uint32_t b3{static_cast<uint32_t>(triggerData[5U]) << 24U};
    return b0 | b1 | b2 | b3;
}

/**
 * @brief   Extracts the log data start time (4 bytes, little-endian, signed) from the raw trigger payload.
 * @details Reads bytes at offsets 6–9 of the payload. Returns 0 on undersized input.
 * @param[in] triggerData  Raw ZAT trigger payload bytes.
 * @return  int32_t — extracted log data start time in seconds.
 */
int32_t ExtractLogDataStartTime(const std::vector<uint8_t>& triggerData) noexcept
{
    if (triggerData.size() < 10U) { return 0; }
    const uint32_t b0{static_cast<uint32_t>(triggerData[6U])};
    const uint32_t b1{static_cast<uint32_t>(triggerData[7U]) << 8U};
    const uint32_t b2{static_cast<uint32_t>(triggerData[8U]) << 16U};
    const uint32_t b3{static_cast<uint32_t>(triggerData[9U]) << 24U};
    return static_cast<int32_t>(b0 | b1 | b2 | b3);
}

/**
 * @brief   Extracts the log data end time (4 bytes, little-endian, signed) from the raw trigger payload.
 * @details Reads bytes at offsets 10–13 of the payload. Returns 0 on undersized input.
 * @param[in] triggerData  Raw ZAT trigger payload bytes.
 * @return  int32_t — extracted log data end time in seconds.
 */
int32_t ExtractLogDataEndTime(const std::vector<uint8_t>& triggerData) noexcept
{
    if (triggerData.size() < 14U) { return 0; }
    const uint32_t b0{static_cast<uint32_t>(triggerData[10U])};
    const uint32_t b1{static_cast<uint32_t>(triggerData[11U]) << 8U};
    const uint32_t b2{static_cast<uint32_t>(triggerData[12U]) << 16U};
    const uint32_t b3{static_cast<uint32_t>(triggerData[13U]) << 24U};
    return static_cast<int32_t>(b0 | b1 | b2 | b3);
}

