// ============================================================
// FindServiceSdmap
// ============================================================

/**
 * @brief   Locates the SDMAP data service for receiving map data.
 * @details Resolves the SDMAP service instance identifier, validates it, initiates
 *          non-blocking service discovery, and registers the OnSdmapServiceAvailable
 *          availability callback. When the service becomes available the callback
 *          creates a proxy and subscribes HandleSdmapDataEvt. If the instance
 *          identifier cannot be resolved or StartFindService fails, the error is
 *          logged and the function returns without modifying shared state.
 * @pre     ProbeComm has been constructed with a valid variant.
 * @post    SDMAP event subscription is active on success.
 * @throws  None.
 * @note    Called by: ProbeApp. Call condition: Startup.
 * @requirements SWR-REQ-03-01-002
 * @see     HandleSdmapDataEvt
 */
void ProbeComm::FindServiceSdmap() noexcept
{
    // Step 1: Resolve SDMAP service instance identifier from configuration
    const ServiceInstanceId sdmapInstanceId{ResolveServiceInstanceId("SDMAP_Service")};

    // Step 2: Validate resolved instance identifier
    if (!sdmapInstanceId.isValid())
    {
        LogError("FindServiceSdmap: SDMAP service instance resolution failed");
        return;
    }

    // Step 3: Initiate service discovery for SDMAP_Service
    const bool discoveryResult{StartFindService("SDMAP_Service", sdmapInstanceId)};

    // Step 4: Evaluate discovery initiation result
    if (!discoveryResult)
    {
        LogError("FindServiceSdmap: StartFindService for SDMAP returned failure");
        return;
    }

    // Step 5: Register availability callback for SDMAP service handle
    RegisterServiceAvailabilityCallback(
        "SDMAP_Service",
        sdmapInstanceId,
        [this, sdmapInstanceId](std::vector<ServiceHandle> serviceHandles) noexcept
        {
            // BEGIN OnSdmapServiceAvailable

            // Validate received service handles are non-empty
            if (serviceHandles.empty())
            {
                return;
            }

            // Check if a valid matching instance exists
            bool matchFound{false};
            ServiceHandle selectedHandle;

            for (const ServiceHandle& handle : serviceHandles)
            {
                if (handle.instanceId.id == sdmapInstanceId.id)
                {
                    matchFound     = true;
                    selectedHandle = handle;
                    break;
                }
            }

            if (!matchFound)
            {
                return;
            }

            // Create proxy for the discovered service instance
            ServiceProxy sdmapProxy{CreateServiceProxy("SDMAP_Service", selectedHandle)};

            if (!sdmapProxy.valid)
            {
                LogError("FindServiceSdmap: proxy creation failed for SDMAP_Service");
                return;
            }

            // Subscribe to SDMAP data event
            sdmapProxy.SubscribeEvent(
                [this](std::vector<uint8_t> data) noexcept
                {
                    this->HandleSdmapDataEvt(std::move(data));
                });

            // END OnSdmapServiceAvailable
        });

    // Step 6: Return; proxy binding is managed asynchronously
    LogInfo("FindServiceSdmap: SDMAP service discovery initiated successfully");
}

// ============================================================
// OfferServiceProbeEventStt
// ============================================================

/**
 * @brief   Offers the probeEventStt service to allow ZAT to subscribe for trigger acceptance status.
 * @details Resolves the probeEventStt service instance identifier, initialises the
 *          acceptance status arrays and allowedOverlapTriggerNum to their default values,
 *          creates the service skeleton, and calls OfferService. If any step fails the
 *          error is logged and the function returns without setting a global error flag.
 *          The function executes once per startup sequence and is bounded in execution time.
 * @pre     ProbeComm has been constructed with a valid variant.
 * @post    probeEventStt service is offered and available for ZAT subscription.
 * @throws  None.
 * @note    Called by: ProbeApp. Call condition: Startup.
 * @requirements SWR-REQ-03-05-001;SWR-REQ-03-05-003
 * @see     SendTriggerAcceptanceStatusToZAT, SendAllowedOverlapCountToZAT
 */
void ProbeComm::OfferServiceProbeEventStt() noexcept
{
    // Step 1: Resolve probeEventStt service instance identifier
    const ServiceInstanceId probeEventSttInstanceId{
        ResolveServiceInstanceId("probeEventStt_Service")};

    // Step 2: Validate instance identifier
    if (!probeEventSttInstanceId.isValid())
    {
        LogError("OfferServiceProbeEventStt: instance resolution failed");
        return;
    }

    // Step 3: Initialize acceptance status fields to default values
    // acceptedDataTransmissionNum_ is a uint32_t member; initialise to 0x00
    acceptedDataTransmissionNum_ = 0x00U;

    // acceptedCategoryIdentifier_ is a uint32_t member; initialise to 0x00000000
    acceptedCategoryIdentifier_ = 0x00000000U;

    // allowedOverlapTriggerNum_ is the configured overlap limit; default to 1
    allowedOverlapTriggerNum_ = 1;

    // Step 4: Instantiate probeEventStt service skeleton
    const ServiceSkeleton probeEventSttSkeleton{
        CreateServiceSkeleton("probeEventStt_Service", probeEventSttInstanceId)};

    // Step 5: Validate skeleton creation
    if (!probeEventSttSkeleton.valid)
    {
        LogError("OfferServiceProbeEventStt: service skeleton creation failed");
        return;
    }

    // Step 6: Offer the service to allow ZAT to discover and subscribe
    const bool offerResult{probeEventSttSkeleton.OfferService()};

    // Step 7: Evaluate offer result
    if (!offerResult)
    {
        LogError("OfferServiceProbeEventStt: OfferService call failed");
        return;
    }

    // Step 8: Log successful service offering
    LogInfo("OfferServiceProbeEventStt: probeEventStt service offered successfully");
}

// ============================================================
// OfferServiceProbeTrigger
// ============================================================

/**
 * @brief   Offers the PROBE_TRG_Service to allow CameraHost to subscribe for image acquisition triggers.
 * @details Resolves the PROBE_TRG_Service instance identifier, creates the service skeleton,
 *          and calls OfferService. If any step fails the error is logged and the function
 *          returns without blocking startup progression. The function is bounded in execution
 *          and performs no cyclic processing.
 * @pre     ProbeComm has been constructed with a valid variant.
 * @post    PROBE_TRG service is offered and available for CameraHost subscription.
 * @throws  None.
 * @note    Called by: ProbeApp. Call condition: Startup.
 * @requirements SWR-REQ-03-06-001
 * @see     SendImageAcquisitionTriggerToCameraHost
 */
void ProbeComm::OfferServiceProbeTrigger() noexcept
{
    // Step 1: Resolve PROBE_TRG_Service instance identifier
    const ServiceInstanceId probeTrgInstanceId{
        ResolveServiceInstanceId("PROBE_TRG_Service")};

    // Step 2: Validate instance identifier
    if (!probeTrgInstanceId.isValid())
    {
        LogError("OfferServiceProbeTrigger: instance resolution failed");
        return;
    }

    // Step 3: Create PROBE_TRG_Service skeleton
    const ServiceSkeleton probeTrgSkeleton{
        CreateServiceSkeleton("PROBE_TRG_Service", probeTrgInstanceId)};

    // Step 4: Validate skeleton creation
    if (!probeTrgSkeleton.valid)
    {
        LogError("OfferServiceProbeTrigger: skeleton creation failed");
        return;
    }

    // Step 5: Offer PROBE_TRG_Service to CameraHost
    const bool offerResult{probeTrgSkeleton.OfferService()};

    // Step 6: Evaluate offer result
    if (!offerResult)
    {
        LogError("OfferServiceProbeTrigger: OfferService call failed");
        return;
    }

    // Step 7: Log successful offering
    LogInfo("OfferServiceProbeTrigger: PROBE_TRG_Service offered successfully");
}

// ============================================================
// HandleAdasAcoreTriggerEvt
// ============================================================

/**
 * @brief   Receives and processes development event triggers from ZAT at 100 ms periodic cycle.
 * @details Parses the raw trigger payload to extract the upload request flag, transmission
 *          number, category identifier, log start time, and log end time. Applies the
 *          sequential validation chain: upload flag check, per-category limit check (skipped
 *          for GEDR-only triggers), and overlap limit check. On passing all validations,
 *          clamps the log times, updates internal state, increments the per-category counter
 *          for probe triggers, and sets zatTriggerReceived_ to true.
 * @param[in] triggerData  Serialized ZAT trigger payload. Must not be empty.
 *                         Valid range: non-empty byte vector conforming to ZAT trigger format.
 * @pre     FindServiceZatTrigger has been called and subscription is active.
 * @post    Internal trigger state is updated. Event pipeline may be initiated.
 * @throws  None.
 * @note    Called by: ProbeApp. Call condition: Cyclic_100ms.
 * @warning Must not block; all heavy processing is deferred to cyclic tasks.
 * @requirements SWR-REQ-03-02-001;SWR-REQ-03-02-002;SWR-REQ-03-003
 * @see     ValidateTriggerUploadRequestFlag, CheckSameCategoryLimit, CheckOverlapTriggerLimit
 */
void ProbeComm::HandleAdasAcoreTriggerEvt(std::vector<uint8_t> triggerData) noexcept
{
    // Guard: reject undersized payloads before any field extraction
    if (triggerData.empty())
    {
        LogInfo("HandleAdasAcoreTriggerEvt: empty triggerData received, discarding");
        return;
    }

    // Step 1: Parse trigger payload fields
    const uint8_t  parsedFlag           {ExtractDataUploadRequestFlag(triggerData)};
    const uint8_t  parsedTransNum       {ExtractDataTransmissionNum(triggerData)};
    const uint32_t parsedCategoryId     {ExtractCategoryIdentifier(triggerData)};
    const int32_t  parsedLogStartTime   {ExtractLogDataStartTime(triggerData)};
    const int32_t  parsedLogEndTime     {ExtractLogDataEndTime(triggerData)};
    const uint32_t parsedRetentionLimit {GetConfiguredRetentionLimit()};

    // Step 2: Validate upload request flag; reject if zero
    const bool flagValid{ValidateTriggerUploadRequestFlag(parsedFlag)};
    if (!flagValid)
    {
        // No active trigger; return without state modification
        return;
    }

    // Step 3: Determine if trigger is GEDR-only (flag == 2 bypasses category limit)
    const bool isGedrOnly{parsedFlag == static_cast<uint8_t>(2U)};

    // Step 4: Check per-category acceptance limit for probe triggers
    if (!isGedrOnly)
    {
        const bool categoryLimitOk{CheckSameCategoryLimit(parsedCategoryId)};
        if (!categoryLimitOk)
        {
            // Trigger rejected due to per-category limit; do not accept
            LogInfo("HandleAdasAcoreTriggerEvt: category limit reached, trigger rejected");
            return;
        }
    }

    // Step 5: Check overlap trigger limit
    const bool overlapOk{CheckOverlapTriggerLimit()};
    if (!overlapOk)
    {
        // Active event count exceeds allowed overlap; reject trigger
        LogInfo("HandleAdasAcoreTriggerEvt: overlap limit reached, trigger rejected");
        return;
    }

    // Step 6: Clamp log start time to retention limit
    const int32_t effectiveLogStartTime{
        ValidateLogStartTimeClamping(parsedLogStartTime, parsedRetentionLimit)};

    // Step 7: Clamp log end time to maximum allowed value
    const int32_t effectiveLogEndTime{ValidateLogEndTimeClamping(parsedLogEndTime)};

    // Step 8: Accept trigger - update internal state
    dataUploadRequestFlg_       = parsedFlag;
    currentDataTransmissionNum_ = static_cast<uint32_t>(parsedTransNum);
    currentCategoryIdentifier_  = parsedCategoryId;
    effectiveLogStartTime_      = effectiveLogStartTime;
    effectiveLogEndTime_        = effectiveLogEndTime;

    // Step 9: Increment per-category acceptance counter for probe triggers
    if (!isGedrOnly)
    {
        categoryTriggerCountMap_null[parsedCategoryId] =
            categoryTriggerCountMap_null[parsedCategoryId] + 1U;
    }

    // Step 10: Signal that a valid trigger has been received
    zatTriggerReceived_ = true;
    LogInfo("HandleAdasAcoreTriggerEvt: trigger accepted, category=" +
            std::to_string(parsedCategoryId));
}

// ============================================================
// HandleZatRegularUploadData1Evt
// ============================================================

/**
 * @brief   Receives ZAT regular upload data for signal collection.
 * @details Validates that the received data vector is non-empty. If the vector is
 *          empty the payload is silently discarded to prevent downstream buffer
 *          corruption. On a valid non-empty payload the function accepts the data
 *          for the current 100 ms cycle and returns immediately. No decoding,
 *          buffering, or transmission is performed within this function boundary.
 *          Execution is bounded by a single size check and one conditional branch.
 * @param[in] data  Serialized ZAT regular upload payload. Must not be empty.
 *                  Valid range: non-empty byte vector conforming to ZAT regular upload format.
 * @pre     FindServiceZatRegularUpload has been called and subscription is active.
 * @post    Internal regular upload data buffer is updated.
 * @throws  None.
 * @note    Called by: ProbeApp. Call condition: Cyclic_100ms.
 * @requirements SWR-REQ-01-01-001
 * @see     SendContinualShortDataCyclic100ms
 */
void ProbeComm::HandleZatRegularUploadData1Evt(std::vector<uint8_t> data) noexcept
{
    // Step 1: Validate input payload from ZAT_hdfProbeBusOut_Service
    if (data.size() == 0U)
    {
        // No data received in this 100 ms cycle; discard silently
        return;
    }

    // Step 2: Accept ZAT regular upload data payload for this 100 ms cycle
    // Data is now available for downstream signal collection processing.
    // Responsibility boundary ends here per single-responsibility rule.
    (void)data;

    // Step 3: Return - execution is bounded and deterministic
}

