// ============================================================
// Internal-translation-unit constants
// ============================================================

/**
 * @brief   Byte offset of the acceptance status field within the CameraHost answer-back payload.
 * @details Defined by the CameraHost_IMG_Service protocol layout.
 *          Value 0 selects the first byte of the answer-back message.
 */
static constexpr std::size_t ANSWER_BACK_ACCEPTANCE_OFFSET{0U};

/**
 * @brief   Byte offset of the trigger-stage error code (low byte) within the answer-back payload.
 * @details The 16-bit error code occupies bytes [1, 2] in little-endian order.
 */
static constexpr std::size_t ANSWER_BACK_ERROR_CODE_OFFSET{1U};

/**
 * @brief   Byte offset of the PictureSize field (low byte) within the camera image payload.
 * @details The 16-bit picture size occupies bytes [0, 1] in little-endian order.
 */
static constexpr std::size_t PICTURE_SIZE_OFFSET{0U};

/**
 * @brief   Byte offset of the timestamp seconds field within the camera image payload.
 * @details The 32-bit seconds value occupies bytes [2, 5] in little-endian order.
 */
static constexpr std::size_t TIMESTAMP_SEC_OFFSET{2U};

/**
 * @brief   Byte offset of the timestamp milliseconds field within the camera image payload.
 * @details The 32-bit milliseconds value occupies bytes [6, 9] in little-endian order.
 */
static constexpr std::size_t TIMESTAMP_MSEC_OFFSET{6U};

/**
 * @brief   Byte offset of the frame counter field within the camera image payload.
 * @details The 8-bit frame counter occupies byte [10].
 */
static constexpr std::size_t FRAME_COUNTER_OFFSET{10U};

/**
 * @brief   Maximum acceptable size in bytes for an event signal payload.
 * @details Payloads exceeding this bound are discarded to prevent buffer overrun.
 *          Set to 65535 bytes as the upper bound for a single SOME/IP UDP payload.
 */
static constexpr std::size_t MAX_EVENT_SIGNAL_PAYLOAD_SIZE{65535U};

/**
 * @brief   Minimum required size of the answer-back payload to safely extract error code.
 * @details Must contain at least the acceptance byte (offset 0) plus two error-code bytes
 *          (offsets 1 and 2), totalling 3 bytes.
 */
static constexpr std::size_t ANSWER_BACK_MIN_SIZE{3U};

/**
 * @brief   Minimum required size of the image payload to safely extract all header fields.
 * @details Must contain PictureSize (2 bytes) + timestampSec (4 bytes) +
 *          timestampMsec (4 bytes) + frameCounter (1 byte) = 11 bytes minimum.
 */
static constexpr std::size_t IMAGE_PAYLOAD_MIN_SIZE{11U};

// ============================================================
// File-local helper functions (internal linkage)
// ============================================================

/**
 * @brief   Extracts the 16-bit trigger-stage error code from the answer-back payload.
 * @details Reads two bytes starting at ANSWER_BACK_ERROR_CODE_OFFSET in little-endian order
 *          and assembles them into a uint16_t error code value.
 * @param[in] answerData  Raw answer-back payload. Must have size >= ANSWER_BACK_MIN_SIZE.
 * @return  uint16_t — assembled trigger-stage error code.
 * @pre     answerData.size() >= ANSWER_BACK_MIN_SIZE.
 * @post    No state change.
 * @throws  None.
 */
static uint16_t ExtractTriggerErrorCode(const std::vector<uint8_t>& answerData) noexcept
{
    const uint16_t lowByte  = static_cast<uint16_t>(answerData[ANSWER_BACK_ERROR_CODE_OFFSET]);
    const uint16_t highByte = static_cast<uint16_t>(answerData[ANSWER_BACK_ERROR_CODE_OFFSET + 1U]);
    return static_cast<uint16_t>(lowByte | static_cast<uint16_t>(highByte << 8U));
}

/**
 * @brief   Extracts the 16-bit PictureSize field from the camera image payload.
 * @details Reads two bytes at PICTURE_SIZE_OFFSET in little-endian order.
 * @param[in] imageData  Raw image payload. Must have size >= 2.
 * @return  uint16_t — picture size in bytes.
 * @pre     imageData.size() >= 2U.
 * @post    No state change.
 * @throws  None.
 */
static uint16_t ExtractPictureSize(const std::vector<uint8_t>& imageData) noexcept
{
    const uint16_t lowByte  = static_cast<uint16_t>(imageData[PICTURE_SIZE_OFFSET]);
    const uint16_t highByte = static_cast<uint16_t>(imageData[PICTURE_SIZE_OFFSET + 1U]);
    return static_cast<uint16_t>(lowByte | static_cast<uint16_t>(highByte << 8U));
}

/**
 * @brief   Extracts the 32-bit timestamp seconds field from the camera image payload.
 * @details Reads four bytes at TIMESTAMP_SEC_OFFSET in little-endian order.
 * @param[in] imageData  Raw image payload. Must have size >= TIMESTAMP_SEC_OFFSET + 4.
 * @return  uint32_t — timestamp seconds component.
 * @pre     imageData.size() >= TIMESTAMP_SEC_OFFSET + 4U.
 * @post    No state change.
 * @throws  None.
 */
static uint32_t ExtractTimestampSec(const std::vector<uint8_t>& imageData) noexcept
{
    const uint32_t b0 = static_cast<uint32_t>(imageData[TIMESTAMP_SEC_OFFSET]);
    const uint32_t b1 = static_cast<uint32_t>(imageData[TIMESTAMP_SEC_OFFSET + 1U]);
    const uint32_t b2 = static_cast<uint32_t>(imageData[TIMESTAMP_SEC_OFFSET + 2U]);
    const uint32_t b3 = static_cast<uint32_t>(imageData[TIMESTAMP_SEC_OFFSET + 3U]);
    return static_cast<uint32_t>(b0 | (b1 << 8U) | (b2 << 16U) | (b3 << 24U));
}

/**
 * @brief   Extracts the 32-bit timestamp milliseconds field from the camera image payload.
 * @details Reads four bytes at TIMESTAMP_MSEC_OFFSET in little-endian order.
 * @param[in] imageData  Raw image payload. Must have size >= TIMESTAMP_MSEC_OFFSET + 4.
 * @return  uint32_t — timestamp milliseconds component.
 * @pre     imageData.size() >= TIMESTAMP_MSEC_OFFSET + 4U.
 * @post    No state change.
 * @throws  None.
 */
static uint32_t ExtractTimestampMsec(const std::vector<uint8_t>& imageData) noexcept
{
    const uint32_t b0 = static_cast<uint32_t>(imageData[TIMESTAMP_MSEC_OFFSET]);
    const uint32_t b1 = static_cast<uint32_t>(imageData[TIMESTAMP_MSEC_OFFSET + 1U]);
    const uint32_t b2 = static_cast<uint32_t>(imageData[TIMESTAMP_MSEC_OFFSET + 2U]);
    const uint32_t b3 = static_cast<uint32_t>(imageData[TIMESTAMP_MSEC_OFFSET + 3U]);
    return static_cast<uint32_t>(b0 | (b1 << 8U) | (b2 << 16U) | (b3 << 24U));
}

/**
 * @brief   Extracts the 8-bit frame counter field from the camera image payload.
 * @details Reads one byte at FRAME_COUNTER_OFFSET.
 * @param[in] imageData  Raw image payload. Must have size >= FRAME_COUNTER_OFFSET + 1.
 * @return  uint8_t — frame counter value.
 * @pre     imageData.size() >= FRAME_COUNTER_OFFSET + 1U.
 * @post    No state change.
 * @throws  None.
 */
static uint8_t ExtractFrameCounter(const std::vector<uint8_t>& imageData) noexcept
{
    return imageData[FRAME_COUNTER_OFFSET];
}

