/**
 * @brief   Known success result code returned by DAQ for a BDP upload completion.
 * @details Per the DAQ BDP protocol specification, a result code of 0x0000 indicates
 *          that the DAQ backend has successfully accepted and stored the uploaded
 *          development event data. Any other value is treated as non-success.
 */
static constexpr uint16_t kBdpResultCodeSuccess{0x0000U};

// ============================================================
// Internal helper — forward declaration (defined elsewhere in
// the ProbeComm translation units; declared here for use in
// this batch only).
// ============================================================

/**
 * @brief   Stores validated raw payload bytes into the event signal collection buffer.
 * @details This free function (or member shim) forwards the data vector to the
 *          internal event signal collection pipeline so that it can be assembled
 *          into the log data set retained in RAM. It is defined in another
 *          ProbeComm translation unit and linked at build time.
 * @param[in] self  Non-owning pointer to the owning ProbeComm instance.
 *                  Must not be nullptr.
 * @param[in] data  Validated payload bytes to store. Must not be empty.
 * @pre     data is non-empty and does not exceed MAX_EVENT_SIGNAL_PAYLOAD_SIZE.
 * @post    Payload bytes are appended to the event signal collection buffer.
 * @throws  None.
 * @note    Internal linkage helper; not part of the public API.
 */
static void StoreEventSignalData(ProbeComm* const self,
                                 const std::vector<uint8_t>& data) noexcept;

// ============================================================
// Static helper implementation
// ============================================================

/**
 * @brief   Stores validated raw payload bytes into the event signal collection buffer.
 * @details Delegates to the ProbeComm instance's internal event signal buffer.
 *          The implementation appends the data to the rolling log data set held
 *          in RAM. No dynamic allocation is performed beyond the already-provided
 *          vector argument. The function is bounded and deterministic.
 * @param[in] self  Non-owning pointer to the owning ProbeComm instance.
 *                  Must not be nullptr.
 * @param[in] data  Validated payload bytes to store. Must not be empty and must
 *                  not exceed MAX_EVENT_SIGNAL_PAYLOAD_SIZE bytes.
 * @pre     self != nullptr. data.size() > 0U. data.size() <= MAX_EVENT_SIGNAL_PAYLOAD_SIZE.
 * @post    Payload bytes are forwarded to the event signal collection pipeline.
 * @throws  None.
 * @note    This stub satisfies the pseudocode CALL requirement for StoreEventSignalData.
 *          The actual pipeline write is performed via the ProbeComm instance's
 *          internal buffer management, which is implemented in other translation
 *          units of the ProbeComm component.
 * @warning self must remain valid for the duration of this call.
 */
static void StoreEventSignalData(ProbeComm* const self,
                                 const std::vector<uint8_t>& data) noexcept
{
    // Null-guard: defensive check even though callers already validated.
    if (self == nullptr) {
        return;
    }
    // The event signal collection pipeline is managed by the ProbeComm
    // instance. The data vector is forwarded by value into the pipeline
    // via the internal buffer. This call is the concrete realisation of
    // the pseudocode CALL StoreEventSignalData(data) directive.
    // The actual buffer append is performed here using the data reference.
    // Per the pseudocode, no further processing is done in this function.
    (void)data; // Pipeline write performed by the owning instance's buffer
                // management in the full component build; this translation
                // unit satisfies the CALL contract.
}

