// ============================================================

/**
 * @brief   Receives and processes the BDP upload completion result code from DAQ.
 * @details Evaluates resultCode against the known DAQ success indicator
 *          (kBdpResultCodeSuccess == 0x0000). On a confirmed success, invokes
 *          DeleteEventDataAfterDaqSuccess to purge the development event data
 *          associated with this transmission from active process memory.
 *          On any non-success result code, no action is taken within this function;
 *          retry and abort logic is managed externally by EnforceBdpTransmitRetry
 *          and AbortEventDataTransmissionOnRetryExhaustion. The function is
 *          deterministic, bounded, and performs no blocking operations.
 * @param[in] resultCode  BDP upload result code received from DAQ.
 *                        Valid range: uint16_t full range.
 *                        0x0000 indicates success; all other values indicate non-success.
 * @pre     TransmitBdpDataToDAQ has been called for the current event.
 * @post    On success: event data is deleted via DeleteEventDataAfterDaqSuccess.
 *          On non-success: no state change within this function.
 * @throws  None.
 * @note    Called by: ProbeApp. Call condition: Event_Trigger.
 * @requirements SWR-REQ-03-10-001
 * @see     DeleteEventDataAfterDaqSuccess, EnforceBdpTransmitRetry,
 *          AbortEventDataTransmissionOnRetryExhaustion
 */
void ProbeComm::HandleResultBdpEvt(uint16_t resultCode) noexcept
{
    // Step 1: Validate the received result code is within known value range.
    if (resultCode == kBdpResultCodeSuccess) {
        // Step 2: Invoke memory cleanup for the confirmed-successful event data.
        DeleteEventDataAfterDaqSuccess();
    }
    // Step 3: No action on non-success; retry and abort paths handled externally.
    // Step 4: Function returns; no further state change within this unit.
}

// ============================================================
// ValidateTriggerUploadRequestFlag  (PC-029)
// ============================================================

/**
 * @brief   Checks if the data upload request flag is non-zero to determine a valid trigger.
 * @details Pure predicate function. Evaluates whether the provided flag value is
 *          non-zero. A value of 1 indicates a Probe-only trigger, 2 indicates a
 *          GEDR-only trigger, and 3 indicates both. Any non-zero value is treated
 *          as a valid trigger presence indicator. A value of 0 indicates no active
 *          trigger. No state is modified; execution is O(1) and fully bounded.
 * @param[in] flag  Upload request flag value from ZAT trigger data.
 *                  Valid range: [0, 255]; non-zero indicates a valid request.
 *                  Defined values: 0 = no trigger, 1 = Probe, 2 = GEDR, 3 = both.
 * @return  bool — true if flag is non-zero (valid trigger), false if flag is zero.
 * @retval  true   flag != 0; a valid event trigger is present.
 * @retval  false  flag == 0; no active trigger; suppress downstream processing.
 * @pre     None.
 * @post    No state change.
 * @throws  None.
 * @note    Called by: ProbeComm. Call condition: Cyclic_100ms.
 * @requirements SWR-REQ-03-02-002;SWR-REQ-03-003
 * @see     HandleAdasAcoreTriggerEvt
 */
bool ProbeComm::ValidateTriggerUploadRequestFlag(uint8_t flag) const noexcept
{
    // Step 1: Receive input flag of type uint8_t.
    // Step 2: Evaluate flag value.
    if (flag != static_cast<uint8_t>(0U)) {
        // Step 3: Non-zero value means a valid trigger is present (Probe=1, GEDR=2, Both=3).
        return true;
    }
    // Step 4: Zero means no active trigger; suppress downstream processing.
    return false;
}

// ============================================================
// CheckSameCategoryLimit  (PC-030)
// ============================================================

/**
 * @brief   Validates whether the acceptance counter for a category has reached the configurable limit.
 * @details Declares a local variable currentCount initialized to zero. Performs a
 *          lookup in categoryTriggerCountMap_ for the given categoryId. If the
 *          categoryId is not found, currentCount remains zero (below limit, returns
 *          false). If found, the stored count is assigned to currentCount and
 *          compared against sameCategoryLimitPerDC_. Returns true if currentCount
 *          is greater than or equal to sameCategoryLimitPerDC_, signalling rejection.
 *          Returns false if below the limit, signalling acceptance is permitted.
 *          The function does not modify categoryTriggerCountMap_; counter increment
 *          upon acceptance is handled by the calling context in HandleAdasAcoreTriggerEvt.
 *          Execution is deterministic and O(log n) bounded by the map lookup.
 * @param[in] categoryId  Category identifier to check. Valid range: uint32_t full range.
 * @return  bool — true if category limit is reached, false if further triggers are allowed.
 * @retval  true   currentCount >= sameCategoryLimitPerDC_; trigger must be rejected.
 * @retval  false  currentCount < sameCategoryLimitPerDC_; trigger may be accepted.
 * @pre     None.
 * @post    No state change.
 * @throws  None.
 * @note    Called by: ProbeComm. Call condition: Cyclic_100ms.
 *          If sameCategoryLimitPerDC_ is zero, this function always returns true,
 *          effectively rejecting all triggers. This edge case must be addressed
 *          at configuration validation during initialization.
 * @requirements SWR-REQ-03-12-001;SWR-REQ-03-12-002;SWR-REQ-03-12-005;SWR-REQ-03-12-006
 * @see     HandleAdasAcoreTriggerEvt, ResetCategoryCounterOnNewDriveCycle
 */
bool ProbeComm::CheckSameCategoryLimit(uint32_t categoryId) const noexcept
{
    // Step 1: Receive categoryId : uint32_t.
    // Step 2: Attempt lookup of categoryId in categoryTriggerCountMap.
    uint32_t currentCount{0U};

    const auto it = categoryTriggerCountMap_null.find(categoryId);
    if (it != categoryTriggerCountMap_null.cend()) {
        currentCount = it->second;
    } else {
        // Step 3: Category not seen in this driving cycle; count starts at zero.
        currentCount = 0U;
    }

    // Step 4: Compare count against configurable limit.
    if (currentCount >= sameCategoryLimitPerDC_) {
        // Limit reached or exceeded: trigger must be rejected.
        return true;
    }
    // Below limit: trigger may be accepted.
    return false;
}

// ============================================================
// CheckOverlapTriggerLimit  (PC-031)
// ============================================================

/**
 * @brief   Validates whether the active event process count exceeds the allowed overlap limit.
 * @details Reads activeEventProcessCount_ and allowedOverlapTriggerNum_ from the
 *          ProbeComm instance's private members. If activeEventProcessCount_ is
 *          greater than or equal to allowedOverlapTriggerNum_, returns true,
 *          indicating that no additional parallel event processing can be initiated.
 *          If strictly less, returns false, indicating a new parallel event data
 *          generation process may begin. The function does not modify
 *          activeEventProcessCount_; incrementing and decrementing this counter is
 *          managed by the trigger acceptance and event completion paths respectively.
 *          Execution is deterministic, O(1), and fully bounded.
 * @return  bool — true if overlap limit is exceeded, false if further overlap is allowed.
 * @retval  true   activeEventProcessCount_ >= allowedOverlapTriggerNum_; reject trigger.
 * @retval  false  activeEventProcessCount_ < allowedOverlapTriggerNum_; accept trigger.
 * @pre     None.
 * @post    No state change.
 * @throws  None.
 * @note    Called by: ProbeComm. Call condition: Event_Trigger.
 *          If allowedOverlapTriggerNum_ is zero due to a configuration error, this
 *          function always returns true, blocking all event trigger acceptance.
 *          This condition must be detected and corrected at initialization.
 * @requirements SWR-REQ-03-04-003;SWR-REQ-03-04-004
 * @see     HandleAdasAcoreTriggerEvt, SendAllowedOverlapCountToZAT
 */
bool ProbeComm::CheckOverlapTriggerLimit() const noexcept
{
    // Step 1: Read current values of activeEventProcessCount and allowedOverlapTriggerNum.
    // Step 2: Compare active count against allowed overlap limit.
    if (activeEventProcessCount_ >= allowedOverlapTriggerNum_) {
        // Step 3: Overlap limit reached; incoming trigger must be rejected.
        return true;
    }
    // Step 4: Capacity available; trigger may be accepted.
    return false;
}

// ============================================================
// ValidateLogStartTimeClamping  (PC-032)
// ============================================================

/**
 * @brief   Clamps log data start time to the negative of past data retention setting when exceeded.
 * @details Computes the absolute value of startTime into the local variable absStartTime.
 *          Compares absStartTime against CAST_TO_INT32(retentionLimit). If absStartTime
 *          is greater than the cast retention limit, the effective start time is set to
 *          -CAST_TO_INT32(retentionLimit). Otherwise the effective start time is assigned
 *          unchanged from the input. The result is stored in the private member
 *          effectiveLogStartTime_ and also returned to the caller. This ensures the log
 *          data window never reaches beyond available buffer history, preventing access
 *          violations and undefined data states. Execution is deterministic, performs no
 *          dynamic allocation, and completes within a single bounded evaluation.
 * @param[in] startTime       Log data start time in seconds. Valid range: int32_t full range.
 *                            Semantically expected to be zero or negative (pre-trigger offset).
 * @param[in] retentionLimit  Past data retention limit in seconds.
 *                            Valid range: [0, INT32_MAX] (values > INT32_MAX cause
 *                            undefined behaviour on cast and must not be passed).
 * @return  int32_t — clamped or original start time value stored in effectiveLogStartTime_.
 * @retval  -static_cast<int32_t>(retentionLimit)  When |startTime| > retentionLimit.
 * @retval  startTime                               When |startTime| <= retentionLimit.
 * @pre     retentionLimit <= static_cast<uint32_t>(std::numeric_limits<int32_t>::max()).
 * @post    effectiveLogStartTime_ is updated to the clamped or original start time.
 * @throws  None.
 * @note    Called by: ProbeComm. Call condition: Event_Trigger.
 *          If retentionLimit is zero, effectiveLogStartTime_ is clamped to 0 regardless
 *          of input, which is a safe and deterministic default.
 * @requirements SWR-REQ-03-02-003;SWR-REQ-03-17-007
 * @see     ValidateLogEndTimeClamping
 */
int32_t ProbeComm::ValidateLogStartTimeClamping(int32_t startTime,
                                                 uint32_t retentionLimit) const noexcept
{
    // Step 1: Compute the absolute value of the incoming start time.
    // ABS: compute absolute value of startTime using std::abs for int32_t.
    const int32_t absStartTime{(startTime < static_cast<int32_t>(0))
                                    ? -startTime
                                    : startTime};

    // CAST_TO_INT32: cast retentionLimit (uint32_t) to int32_t for signed comparison.
    const int32_t retentionLimitSigned{static_cast<int32_t>(retentionLimit)};

    // Step 2: Compare absolute start time with the past data retention limit.
    int32_t effectiveLogStartTime{0};
    if (absStartTime > retentionLimitSigned) {
        // Step 3a: Clamp to negative retention limit.
        effectiveLogStartTime = -retentionLimitSigned;
    } else {
        // Step 3b: Accept the received start time as-is.
        effectiveLogStartTime = startTime;
    }

    // Step 4: Return the validated effective start time.
    // Also persist into the private member as specified by the pseudocode.
    // The member is declared mutable-compatible via const member function;
    // the pseudocode mandates writing effectiveLogStartTime_ here.
    // Per the pseudocode: effectiveLogStartTime = ... and RETURN effectiveLogStartTime.
    // The private member write is performed via const_cast to honour the pseudocode
    // directive while preserving the const qualifier on the method signature.
    const_cast<ProbeComm*>(this)->effectiveLogStartTime_ = effectiveLogStartTime;

    return effectiveLogStartTime;
}

