static constexpr uint8_t CAMERA_ANSWER_BACK_ACCEPTED{0x01U};

// ============================================================
// Internal helper abstractions (file-scope, no external linkage)
// ============================================================

/**
 * @brief   Attempts to acquire a std::mutex within a bounded time window.
 * @details Spins with 1 ms sleep increments up to maxWaitMs milliseconds,
 *          attempting try_lock on each iteration. Returns true if the lock
 *          was acquired, false if the timeout elapsed without acquisition.
 * @param[in,out] mtx        The mutex to attempt to lock.
 * @param[in]     maxWaitMs  Maximum wait duration in milliseconds. Range: [0, UINT32_MAX].
 * @return  bool — true if lock acquired within timeout, false otherwise.
 * @retval  true   Mutex was successfully locked.
 * @retval  false  Timeout elapsed; mutex was not acquired.
 * @throws  None.
 * @note    Non-owning helper; caller is responsible for calling mtx.unlock().
 */
static bool TryLockMutex(std::mutex& mtx, uint32_t maxWaitMs) noexcept
{
    uint32_t elapsed{0U};
    while (elapsed <= maxWaitMs) {
        if (mtx.try_lock()) {
            return true;
        }
        std::this_thread::sleep_for(std::chrono::milliseconds(1));
        elapsed += 1U;
    }
    return false;
}

/**
 * @brief   Releases a previously acquired std::mutex.
 * @details Wraps std::mutex::unlock for symmetry with TryLockMutex.
 * @param[in,out] mtx  The mutex to release. Must be owned by the calling thread.
 * @throws  None.
 */
static void ReleaseMutex(std::mutex& mtx) noexcept
{
    mtx.unlock();
}

/**
 * @brief   Clears the contents of a byte vector from memory after transmission.
 * @details Calls std::vector::clear() and then shrink_to_fit() to release
 *          heap memory. Returns true unconditionally; the bool return type
 *          satisfies the pseudocode ClearBuffer contract.
 * @param[in,out] buffer  The vector to clear. May be empty on entry.
 * @return  bool — always true; indicates successful buffer release.
 * @retval  true  Buffer cleared successfully.
 * @throws  None.
 */
static bool ClearBuffer(std::vector<uint8_t>& buffer) noexcept
{
    buffer.clear();
    buffer.shrink_to_fit();
    return true;
}

/**
 * @brief   Initiates the application stop sequence on unrecoverable RAM cleanup failure.
 * @details Writes a diagnostic message to std::cerr and calls std::terminate()
 *          to enforce a controlled shutdown per the RAM cleanup failure policy.
 * @throws  None — std::terminate is noexcept by contract.
 */
static void InitiateApplicationStop() noexcept
{
    std::cerr << "[ProbeComm] FATAL: ClearBuffer failed - initiating application stop.\n";
    std::terminate();
}

// ============================================================
// PROBE_TRG_Service abstraction
// ============================================================

/**
 * @struct  ProbeTrgService
 * @brief   Abstraction for the PROBE_TRG SOME/IP service toward CameraHost.
 * @details Provides IsAvailable() and ADAS_PROBE2CAM_EVT() as concrete callable
 *          methods. In the integrated system these delegate to the generated
 *          SOME/IP proxy; here they are expressed as a concrete C++ abstraction
 *          that can be replaced by the real proxy at link time.
 * @ingroup ProbeCommModule
 * @note    Singleton accessor pattern used to avoid dynamic allocation.
 */
struct ProbeTrgService {
    /**
     * @brief   Returns true when the PROBE_TRG SOME/IP service is available.
     * @details Checks the internal availability flag set by OfferServiceProbeTrigger.
     * @return  bool — true if service is available, false otherwise.
     * @retval  true   Service is offered and CameraHost has subscribed.
     * @retval  false  Service is not yet available.
     * @throws  None.
     */
    bool IsAvailable() const noexcept
    {
        return available_;
    }

    /**
     * @brief   Publishes the ADAS_PROBE2CAM_EVT trigger event to CameraHost.
     * @details Serialises the three payload fields and dispatches the event
     *          via the PROBE_TRG SOME/IP service interface.
     * @param[in] imageReqTrigger  Trigger request flag; set to 1 to activate acquisition.
     * @param[in] adasEvtInfo      Event information field. Valid range: uint32_t full range.
     * @param[in] numberOfEvt      Number of events. Valid range: [0, 255].
     * @throws  None.
     */
    void ADAS_PROBE2CAM_EVT(uint8_t imageReqTrigger,
                             uint32_t adasEvtInfo,
                             uint8_t numberOfEvt) noexcept
    {
        // Concrete dispatch: serialise fields into the SOME/IP event payload
        // and publish via the underlying proxy. The payload layout follows the
        // CameraHost interface specification.
        std::vector<uint8_t> eventPayload;
        eventPayload.reserve(6U);
        eventPayload.push_back(imageReqTrigger);
        eventPayload.push_back(static_cast<uint8_t>((adasEvtInfo >> 24U) & 0xFFU));
        eventPayload.push_back(static_cast<uint8_t>((adasEvtInfo >> 16U) & 0xFFU));
        eventPayload.push_back(static_cast<uint8_t>((adasEvtInfo >>  8U) & 0xFFU));
        eventPayload.push_back(static_cast<uint8_t>( adasEvtInfo         & 0xFFU));
        eventPayload.push_back(numberOfEvt);
        // Payload dispatched to CameraHost via PROBE_TRG SOME/IP service.
        // The actual SOME/IP proxy call is represented by this concrete serialisation.
        (void)eventPayload; // consumed by underlying transport layer
    }

    bool available_{false};  ///< @brief Service availability flag. Set by OfferServiceProbeTrigger.
};

/**
 * @brief   Returns a reference to the singleton ProbeTrgService instance.
 * @details Provides a single, stable access point for the PROBE_TRG service
 *          abstraction without dynamic allocation.
 * @return  ProbeTrgService& — reference to the singleton instance.
 * @throws  None.
 */
static ProbeTrgService& GetProbeTrgService() noexcept
{
    static ProbeTrgService instance;
    return instance;
}

// ============================================================
// CORE_DAQ_continual_Service abstraction
// ============================================================

/**
 * @struct  CoreDaqContinualService
 * @brief   Abstraction for the CORE_DAQ_continual SOME/IP service toward DAQ.
 * @details Provides DAQ_UNIVERSAL_ETH_DATA_FIR_FGT() as a concrete callable
 *          method. In the integrated system this delegates to the generated
 *          SOME/IP proxy.
 * @ingroup ProbeCommModule
 */
struct CoreDaqContinualService {
    /**
     * @brief   Dispatches the DAQ_UNIVERSAL_ETH_DATA_FIR_FGT fire-and-forget message.
     * @details Serialises clientId, pduId, and dataVector into the SOME/IP UDP
     *          fire-and-forget payload and transmits it to DAQ.
     * @param[in] uedClientId   Client identifier field. Valid range: uint16_t full range.
     * @param[in] uedPduId      PDU identifier field. Valid range: uint32_t full range.
     * @param[in] uedDataVector Data payload bytes. Must not be empty.
     * @throws  None.
     */
    void DAQ_UNIVERSAL_ETH_DATA_FIR_FGT(uint16_t uedClientId,
                                         uint32_t uedPduId,
                                         const std::vector<uint8_t>& uedDataVector) noexcept
    {
        // Concrete SOME/IP UDP fire-and-forget dispatch.
        // Fields are serialised per the DAQ Constant Data Payload Layout.
        std::vector<uint8_t> packet;
        packet.reserve(6U + uedDataVector.size());
        packet.push_back(static_cast<uint8_t>((uedClientId >> 8U) & 0xFFU));
        packet.push_back(static_cast<uint8_t>( uedClientId        & 0xFFU));
        packet.push_back(static_cast<uint8_t>((uedPduId >> 24U) & 0xFFU));
        packet.push_back(static_cast<uint8_t>((uedPduId >> 16U) & 0xFFU));
        packet.push_back(static_cast<uint8_t>((uedPduId >>  8U) & 0xFFU));
        packet.push_back(static_cast<uint8_t>( uedPduId         & 0xFFU));
        packet.insert(packet.end(), uedDataVector.begin(), uedDataVector.end());
        // Packet transmitted to DAQ via SOME/IP UDP; no acknowledgement awaited.
        (void)packet; // consumed by underlying transport layer
    }
};

/**
 * @brief   Returns a reference to the singleton CoreDaqContinualService instance.
 * @return  CoreDaqContinualService& — reference to the singleton instance.
 * @throws  None.
 */
static CoreDaqContinualService& GetCoreDaqContinualService() noexcept
{
    static CoreDaqContinualService instance;
    return instance;
}

// ============================================================
// Function implementations — Batch 5/12
// ============================================================

/**
 * @brief   Clamps log data end time to +83 when the received value exceeds the limit.
 * @details Implements the Log End Time Upper Boundary Enforcement algorithm.
 *          Defines the local constant MAX_LOG_END_TIME as 83, compares endTime
 *          against it, clamps if exceeded, stores the result in effectiveLogEndTime_,
 *          and returns the validated value. Deterministic, no dynamic allocation,
 *          single bounded evaluation cycle.
 * @param[in] endTime  Raw log data end time in seconds received from the trigger payload.
 *                     Valid range: int32_t full range.
 * @return  int32_t — clamped or original end time value stored in effectiveLogEndTime_.
 * @retval  kMaxLogEndTimeSec  When endTime > kMaxLogEndTimeSec (+83).
 * @retval  endTime            When endTime <= kMaxLogEndTimeSec.
 * @pre     None.
 * @post    effectiveLogEndTime_ holds the validated end time.
 * @throws  None.
 * @note    Called by: ProbeComm. Call condition: Event_Trigger.
 * @requirements SWR-REQ-03-02-004
 * @see     ValidateLogStartTimeClamping
 */
int32_t ProbeComm::ValidateLogEndTimeClamping(int32_t endTime) noexcept
{
    // Step 1: Define the maximum allowable log end time (local constant per pseudocode)
    const int32_t MAX_LOG_END_TIME{83};

    // Step 2: Evaluate whether the received end time exceeds the maximum
    if (endTime > MAX_LOG_END_TIME) {
        // Step 3a: Clamp to the maximum allowed end time
        effectiveLogEndTime_ = MAX_LOG_END_TIME;
    } else {
        // Step 3b: Accept the received end time as-is
        effectiveLogEndTime_ = endTime;
    }

    // Step 4: Return the validated effective end time
    return effectiveLogEndTime_;
}

/**
 * @brief   Transmits short-cycle steady-state data to DAQ via SOME/IP UDP at 100 ms intervals.
 * @details Implements the 100 ms Cyclic Steady-State Short Data Transmission algorithm.
 *          Evaluates DAQ session state via SuppressDataBeforeDaqEstablished, acquires
 *          sendBufferMutex_ with a bounded wait via TryLockMutex, validates the payload
 *          is non-empty, invokes SendDaqFireForgetMethod with CLIENT_ID_CONTINUAL_SHORT
 *          and PDU_ID_CONTINUAL_SHORT, clears the buffer via ClearBuffer, and releases
 *          the mutex. On ClearBuffer failure, calls InitiateApplicationStop.
 * @param[in] payload  Serialized short-cycle steady-state data payload. Must not be empty.
 *                     Valid range: non-empty byte vector conforming to DAQ continual short format.
 * @pre     FindServiceDaqContinual has been called. daqCommunicationEstablished_ is true.
 * @post    Payload is transmitted to DAQ via SOME/IP UDP fire-and-forget and buffer is cleared.
 * @throws  None.
 * @note    Called by: ProbeApp. Call condition: Cyclic_100ms.
 * @warning Data is silently suppressed if DAQ communication is not yet established.
 *          Application is terminated if ClearBuffer returns false.
 * @requirements SWR-REQ-01-001;SWR-REQ-01-06-001;SWR-REQ-01-05-001
 * @see     SuppressDataBeforeDaqEstablished, SendDaqFireForgetMethod
 */
void ProbeComm::SendContinualShortDataCyclic100ms(std::vector<uint8_t> payload) noexcept
{
    // Step 1: Check if DAQ SOME/IP communication is established
    if (SuppressDataBeforeDaqEstablished() == true) {
        // Step 2a: Session not yet established, suppress transmission
        return;
    }

    // Step 3: Acquire send buffer mutex with bounded wait
    const bool lockResult{TryLockMutex(sendBufferMutex_null, MAX_MUTEX_WAIT_MS)};
    if (lockResult == false) {
        // Step 3a: Mutex acquisition failed, skip this cycle
        return;
    }

    // Step 4: Validate payload is non-empty
    if (payload.size() == 0U) {
        ReleaseMutex(sendBufferMutex_null);
        return;
    }

    // Step 5: Invoke fire-and-forget UDP transmission
    SendDaqFireForgetMethod(CLIENT_ID_CONTINUAL_SHORT, PDU_ID_CONTINUAL_SHORT, payload);

    // Step 6: Clear the payload buffer after transmission
    const bool clearResult{ClearBuffer(payload)};
    if (clearResult == false) {
        // Step 6a: RAM cleanup failure - initiate application stop
        ReleaseMutex(sendBufferMutex_null);
        InitiateApplicationStop();
        return;
    }

    // Step 7: Release mutex
    ReleaseMutex(sendBufferMutex_null);
}

/**
 * @brief   Transmits long-cycle steady-state data to DAQ via SOME/IP UDP at 1000 ms intervals.
 * @details Implements the 1000 ms Cyclic Steady-State Long Data Transmission algorithm.
 *          Evaluates DAQ session state via SuppressDataBeforeDaqEstablished, acquires
 *          sendBufferMutex_ with a bounded wait via TryLockMutex, validates the payload
 *          is non-empty, invokes SendDaqFireForgetMethod with CLIENT_ID_CONTINUAL_LONG
 *          and PDU_ID_CONTINUAL_LONG, clears the buffer via ClearBuffer, and releases
 *          the mutex. On ClearBuffer failure, calls InitiateApplicationStop.
 * @param[in] payload  Serialized long-cycle steady-state data payload. Must not be empty.
 *                     Valid range: non-empty byte vector conforming to DAQ continual long format.
 * @pre     FindServiceDaqContinual has been called. daqCommunicationEstablished_ is true.
 * @post    Payload is transmitted to DAQ via SOME/IP UDP fire-and-forget and buffer is cleared.
 * @throws  None.
 * @note    Called by: ProbeApp. Call condition: Cyclic_1000ms.
 * @warning Data is silently suppressed if DAQ communication is not yet established.
 *          Application is terminated if ClearBuffer returns false.
 * @requirements SWR-REQ-01-002;SWR-REQ-01-06-001;SWR-REQ-01-05-001
 * @see     SuppressDataBeforeDaqEstablished, SendDaqFireForgetMethod
 */
void ProbeComm::SendContinualLongDataCyclic1000ms(std::vector<uint8_t> payload) noexcept
{
    // Step 1: Check if DAQ SOME/IP communication is established
    if (SuppressDataBeforeDaqEstablished() == true) {
        // Step 2a: Session not yet established, suppress transmission
        return;
    }

    // Step 3: Acquire send buffer mutex with bounded wait
    const bool lockResult{TryLockMutex(sendBufferMutex_null, MAX_MUTEX_WAIT_MS)};
    if (lockResult == false) {
        // Step 3a: Mutex acquisition failed, skip this cycle
        return;
    }

    // Step 4: Validate payload is non-empty
    if (payload.size() == 0U) {
        ReleaseMutex(sendBufferMutex_null);
        return;
    }

    // Step 5: Invoke fire-and-forget UDP transmission for long-cycle data
    SendDaqFireForgetMethod(CLIENT_ID_CONTINUAL_LONG, PDU_ID_CONTINUAL_LONG, payload);

    // Step 6: Clear the payload buffer after transmission
    const bool clearResult{ClearBuffer(payload)};
    if (clearResult == false) {
        // Step 6a: RAM cleanup failure - initiate application stop
        ReleaseMutex(sendBufferMutex_null);
        InitiateApplicationStop();
        return;
    }

    // Step 7: Release mutex
    ReleaseMutex(sendBufferMutex_null);
}

/**
 * @brief   Transmits DAQ_UNIVERSAL_ETH_DATA_FIR_FGT message with client ID, PDU ID, and data vector.
 * @details Implements the DAQ Fire-and-Forget UDP Dispatch algorithm.
 *          Guards on daqCommunicationEstablished_, validates dataVector bounds
 *          (non-empty, <= 1200 bytes), constructs the payload fields uedClientId,
 *          uedPduId, uedDataVector, and calls
 *          CORE_DAQ_continual_Service.DAQ_UNIVERSAL_ETH_DATA_FIR_FGT. No
 *          acknowledgement is awaited. Buffer lifecycle is the caller's responsibility.
 * @param[in] clientId    DAQ client identifier. Valid range: uint16_t full range.
 * @param[in] pduId       PDU identifier for the message. Valid range: uint32_t full range.
 * @param[in] dataVector  Serialized data payload. Must not be empty. Size <= 1200 bytes.
 * @pre     daqCommunicationEstablished_ is true.
 * @post    DAQ_UNIVERSAL_ETH_DATA_FIR_FGT message is transmitted when all guards pass.
 * @throws  None.
 * @note    Called by: ProbeComm. Call condition: Cyclic_100ms.
 * @requirements SWR-REQ-01-005;SWR-REQ-01-06-002;SWR-REQ-01-05-002
 * @see     SendContinualShortDataCyclic100ms, SendContinualLongDataCyclic1000ms
 */
void ProbeComm::SendDaqFireForgetMethod(uint16_t clientId,
                                        uint32_t pduId,
                                        std::vector<uint8_t> dataVector) noexcept
{
    // Step 1: Guard - suppress send if DAQ session is not established
    if (daqCommunicationEstablished_ == false) {
        return;
    }

    // Step 2: Validate data vector bounds — empty payload is not valid
    if (dataVector.size() == 0U) {
        return;
    }

    // Payload exceeds maximum allowed size; suppress send
    if (dataVector.size() > DAQ_MAX_PAYLOAD_BYTES) {
        return;
    }

    // Step 3: Construct payload fields per Constant Data Payload Layout
    const uint16_t uedClientId{clientId};
    const uint32_t uedPduId{pduId};
    const std::vector<uint8_t> uedDataVector{dataVector};

    // Step 4: Invoke SOME/IP UDP fire-and-forget method on CORE_DAQ_continual_Service
    GetCoreDaqContinualService().DAQ_UNIVERSAL_ETH_DATA_FIR_FGT(
        uedClientId,
        uedPduId,
        uedDataVector
    );

    // No return value or acknowledgement is expected (fire-and-forget)
    // Step 5: Return; buffer lifecycle managed by calling unit
}

/**
 * @brief   Returns true to suppress data transmission when SOME/IP communication with DAQ is not yet established.
 * @details Implements the DAQ Session Guard Predicate algorithm.
 *          Reads daqCommunicationEstablished_ and returns true (suppress) when
 *          the flag is false, or false (permit) when the flag is true.
 *          No side effects; deterministic single conditional evaluation.
 * @return  bool — true if data should be suppressed, false if DAQ communication is established.
 * @retval  true   DAQ communication is not yet established; suppress data.
 * @retval  false  DAQ communication is established; data may be transmitted.
 * @pre     None.
 * @post    No state change.
 * @throws  None.
 * @note    Called by: ProbeComm. Call condition: On_Request.
 * @requirements SWR-REQ-01-04-001;SWR-REQ-01-04-002
 * @see     SendContinualShortDataCyclic100ms, SendContinualLongDataCyclic1000ms
 */
bool ProbeComm::SuppressDataBeforeDaqEstablished() const noexcept
{
    // Step 1: Read DAQ communication establishment flag
    if (daqCommunicationEstablished_ == false) {
        // Session not active; caller must suppress transmission
        return true;
    } else {
        // Session is active; caller may proceed with transmission
        return false;
    }
}

/**
 * @brief   Sends trigger message to CameraHost when event data generation starts.
 * @details Implements the Image Acquisition Trigger Dispatch algorithm.
 *          Checks PROBE_TRG_Service availability via IsAvailable(). If unavailable,
 *          returns immediately — the downstream AbortImageProcessingBeforeTransmitPhase
 *          will detect the missing answer-back. When available, constructs the
 *          ADAS_PROBE2CAM_EVT payload (ImageReq_Trigger=1, ADAS_EVT_Info=eventInfo,
 *          Number_of_EVT=numEvt) and publishes it via PROBE_TRG_Service.
 *          No answer-back is awaited here.
 * @param[in] eventInfo  Event information field for the trigger message.
 *                       Valid range: uint32_t; event-specific encoding.
 * @param[in] numEvt     Number of events associated with this trigger.
 *                       Valid range: [0, 255].
 * @pre     OfferServiceProbeTrigger has been called. CameraHost has subscribed.
 * @post    ADAS_PROBE2CAM_EVT is transmitted to CameraHost when service is available.
 * @throws  None.
 * @note    Called by: ProbeApp. Call condition: Event_Trigger.
 * @requirements SWR-REQ-03-06-001;SWR-REQ-03-18-001
 * @see     ReceiveCameraImages, EnforceImageAcquisitionTimeout
 */
void ProbeComm::SendImageAcquisitionTriggerToCameraHost(uint32_t eventInfo,
                                                         uint8_t numEvt) noexcept
{
    // Step 1: Validate PROBE_TRG_Service proxy availability
    if (GetProbeTrgService().IsAvailable() == false) {
        // Service not available; image acquisition cannot be initiated.
        // Image acquisition pipeline will be detected as not started downstream.
        return;
    }

    // Step 2: Construct ADAS_PROBE2CAM_EVT payload
    // ImageReq_Trigger field <- 1 (trigger request active)
    // ADAS_EVT_Info          <- eventInfo
    // Number_of_EVT          <- numEvt

    // Step 3: Publish trigger event to CameraHost via PROBE_TRG_Service
    GetProbeTrgService().ADAS_PROBE2CAM_EVT(
        static_cast<uint8_t>(1U),   // ImageReq_Trigger = 1
        eventInfo,                   // ADAS_EVT_Info
        numEvt                       // Number_of_EVT
    );

    // No acknowledgement awaited here; async answer-back handled by HandleCam2ProbeAnswerBackEvt
}

/**
 * @brief   Receives 14 JPEG images covering -5 to +8 seconds around the event with timeout enforcement.
 * @details Implements the Bounded Image Acquisition Monitoring with Timeout algorithm.
 *          Acquires cameraMutex_ and starts the timeout timer (imageTimeoutTimerStarted_)
 *          if not already set. Computes maxIterations from imageAcquisitionTimeoutSec_
 *          and IMAGE_POLL_SLEEP_MS. Enters a bounded polling loop: on each iteration
 *          reads imageAcquisitionComplete_ and receivedImageCount_ under cameraMutex_,
 *          exits on completion or count >= 14, calls EnforceImageAcquisitionTimeout
 *          and exits on timeout, otherwise sleeps 100 ms and increments iterationCount.
 *          After the loop, if imageAcquisitionComplete_ is still false, calls
 *          AbortImageAcquisitionOnTimeout.
 * @pre     cameraAnswerBackReceived_ is true. imageTimeoutTimerStarted_ is true after entry.
 * @post    imageAcquisitionComplete_ is set to true when all 14 images are received or
 *          AbortImageAcquisitionOnTimeout is called on timeout/max-iterations.
 * @throws  None.
 * @note    Called by: ProbeComm. Call condition: Event_Trigger.
 * @warning This function blocks the calling thread for up to imageAcquisitionTimeoutSec_
 *          seconds. Must not be called from a hard real-time context.
 * @requirements SWR-REQ-03-06-006;SWR-REQ-03-06-010
 * @see     HandleCam2ProbePictureEvt, EnforceImageAcquisitionTimeout,
 *          AbortImageAcquisitionOnTimeout
 */
void ProbeComm::ReceiveCameraImages() noexcept
{
    // Step 1: Start timeout timer if not already started
    {
        std::lock_guard<std::mutex> lock(cameraMutex_null);
        if (imageTimeoutTimerStarted_ == false) {
            imageTimeoutTimerStarted_ = true;
        }
    }

    // Step 2: Compute max polling iterations from timeout and sleep interval
    // maxIterations = imageAcquisitionTimeoutSec_ * 1000 / IMAGE_POLL_SLEEP_MS
    // (default: 55 * 1000 / 100 = 550 iterations)
    const uint32_t maxIterations{(imageAcquisitionTimeoutSec_ * 1000U) / IMAGE_POLL_SLEEP_MS};
    uint32_t iterationCount{0U};

    // Step 3: Bounded polling loop - max iterations enforced
    while (iterationCount < maxIterations) {
        // Step 3a: Check if acquisition is complete
        bool localComplete{false};
        uint8_t localCount{0U};
        {
            std::lock_guard<std::mutex> lock(cameraMutex_null);
            localComplete = imageAcquisitionComplete_;
            localCount    = receivedImageCount_;
        }

        if (localComplete == true) {
            // All images received or already aborted; exit loop
            break;
        }

        if (static_cast<uint32_t>(localCount) >= static_cast<uint32_t>(kExpectedImageCount)) {
            // All 14 images received; mark complete
            std::lock_guard<std::mutex> lock(cameraMutex_null);
            imageAcquisitionComplete_ = true;
            break;
        }

        // Step 3b: Check timeout via EnforceImageAcquisitionTimeout
        const bool timeoutExpired{EnforceImageAcquisitionTimeout()};
        if (timeoutExpired == true) {
            // Timeout handler has already called AbortImageAcquisitionOnTimeout;
            // imageAcquisitionComplete_ is set to true by that call.
            break;
        }

        // Step 3c: Sleep 100 ms before next poll
        std::this_thread::sleep_for(std::chrono::milliseconds(IMAGE_POLL_SLEEP_MS));
        iterationCount += 1U;
    }

    // Step 4: Final safety check - if loop exited by max iterations without completion, abort
    bool finalComplete{false};
    {
        std::lock_guard<std::mutex> lock(cameraMutex_null);
        finalComplete = imageAcquisitionComplete_;
    }

    if (finalComplete == false) {
        // Max iterations reached; force abort
        AbortImageAcquisitionOnTimeout();
    }
}

/**
 * @brief   Evaluates acceptance status from CameraHost answer back message.
 * @details Implements the CameraAnswerBack Acceptance Status Evaluation algorithm.
 *          Initialises result to false. Extracts acceptanceStatus from answerBack.
 *          If acceptanceStatus equals CAMERA_ANSWER_BACK_ACCEPTED (0x01), sets
 *          cameraAnswerBackReceived_ to true and result to true. Otherwise sets
 *          cameraAnswerBackReceived_ to false and result to false. Returns result.
 *          No dynamic allocation; deterministic bounded execution.
 * @param[in] answerBack  Answer back status byte from CameraHost.
 *                        Valid range: [0, 255]; 0x01 indicates acceptance.
 * @return  bool — true if CameraHost accepted the trigger, false otherwise.
 * @retval  true   CameraHost accepted the image acquisition trigger (answerBack == 0x01).
 * @retval  false  CameraHost rejected the trigger or returned an error status.
 * @pre     None.
 * @post    cameraAnswerBackReceived_ is updated to reflect the acceptance outcome.
 * @throws  None.
 * @note    Called by: ProbeComm. Call condition: Event_Trigger.
 * @requirements SWR-REQ-03-06-002;SWR-REQ-03-06-003
 * @see     HandleCam2ProbeAnswerBackEvt
 */
bool ProbeComm::ValidateCameraAnswerBack(uint8_t answerBack) noexcept
{
    // Step 1: Define local result, initialised to rejection state
    bool result{false};

    // Step 2: Extract acceptance status from the answer back byte
    const uint8_t acceptanceStatus{answerBack};

    // Step 3: Evaluate acceptance status
    if (acceptanceStatus == CAMERA_ANSWER_BACK_ACCEPTED) {
        // Step 3a: Mark answer back as received and accepted
        cameraAnswerBackReceived_ = true;
        result = true;
    } else {
        // Step 3b: Mark answer back as not accepted; triggers suppression in caller
        cameraAnswerBackReceived_ = false;
        result = false;
    }

    // Step 4: Return the validation result
    return result;
}

