// IMPLEMENT: BuildPayloadCategoryOptionalAndEventList
// Unit ID  : PC-049
// ============================================================

/**
 * @brief   Constructs the first event payload with category data and event list.
 * @details Assembles EventDataType 001 by embedding the EventDataType_Category_Header_Identifier,
 *          the currentDataTransmissionNum_ (serialized as uint8_t), the currentCategoryIdentifier_
 *          (serialized as four little-endian bytes), and the raw triggerData bytes. The assembled
 *          buffer is then submitted to SegmentPayloadIfExceedsMaxSize. The first (or only) segment
 *          is returned to the caller; multi-segment iteration is the caller's responsibility.
 *          If triggerData is empty, a header-only payload is constructed and the condition is
 *          logged to std::cerr. If segmentation produces no output, an empty vector is returned.
 * @param[in] triggerData  Serialized ZAT trigger payload providing category optional data and
 *                         event list fields. Valid range: non-empty byte vector conforming to
 *                         ZAT trigger format. An empty vector results in a header-only payload.
 * @return  std::vector<uint8_t> — first segment of the assembled EventDataType 001 payload,
 *          or an empty vector if segmentation produced no output.
 * @retval  non-empty  First segment of the assembled and segmented category payload.
 * @retval  empty      SegmentPayloadIfExceedsMaxSize returned no segments (fault condition).
 * @pre     currentCategoryIdentifier_ and currentDataTransmissionNum_ are set to valid values.
 * @post    No state change beyond segmentNumber_ and totalSegments_ updated by segmentation.
 * @throws  None.
 * @note    Called by: ProbeComm. Call condition: Event_Trigger.
 * @warning If triggerData is empty, the payload contains only the header fields.
 *          The transmission layer receives a structurally valid but minimal payload.
 * @requirements SWR-REQ-03-07-001;SWR-REQ-03-07-003
 * @see     SegmentPayloadIfExceedsMaxSize, FillHeaderEventDataType001
 */
std::vector<uint8_t> ProbeComm::BuildPayloadCategoryOptionalAndEventList(
    std::vector<uint8_t> triggerData) const noexcept
{
    // Step 1: Initialize local assembly buffer
    std::vector<uint8_t> assembledPayload;

    // Step 2: Append EventDataType 001 header identifier
    assembledPayload.push_back(EventDataType_Category_Header_Identifier);

    // Step 3: Embed currentDataTransmissionNum (uint8_t) into header
    assembledPayload.push_back(static_cast<uint8_t>(currentDataTransmissionNum_));

    // Step 4: Embed currentCategoryIdentifier (uint32_t) into header as little-endian bytes
    assembledPayload.push_back(static_cast<uint8_t>(currentCategoryIdentifier_ & 0xFFU));
    assembledPayload.push_back(static_cast<uint8_t>((currentCategoryIdentifier_ >> 8U) & 0xFFU));
    assembledPayload.push_back(static_cast<uint8_t>((currentCategoryIdentifier_ >> 16U) & 0xFFU));
    assembledPayload.push_back(static_cast<uint8_t>((currentCategoryIdentifier_ >> 24U) & 0xFFU));

    // Step 5: Validate triggerData before embedding
    if (triggerData.empty())
    {
        // Log missing input; continue with header-only payload
        std::cerr << "[ProbeComm] BuildPayloadCategoryOptionalAndEventList: triggerData is empty; constructing header-only payload.\n";
        // No error propagation; caller handles downstream consequence
    }
    else
    {
        // Step 6: Append category optional data and event list from triggerData
        assembledPayload.insert(assembledPayload.end(), triggerData.begin(), triggerData.end());
    }

    // Step 7: Invoke segmentation logic
    // NOTE: SegmentPayloadIfExceedsMaxSize is non-const (updates segmentNumber_/totalSegments_),
    // but this function is declared const. We cast away const to call the non-const member
    // as required by the pseudocode contract. This is safe because the only mutation is to
    // segmentation tracking state, not to observable logical state of the payload assembly.
    // DEVIATION: const_cast required because SegmentPayloadIfExceedsMaxSize is non-const per header.
    // RATIONALE: Pseudocode mandates the call; segmentation state is internal bookkeeping only.
    ProbeComm* mutableThis = const_cast<ProbeComm*>(this);
    std::vector<std::vector<uint8_t>> segmentedOutput =
        mutableThis->SegmentPayloadIfExceedsMaxSize(assembledPayload);

    // Step 8: Return first (or only) segment for this function's single-payload contract
    if (!segmentedOutput.empty())
    {
        return segmentedOutput[0];  // Caller iterates remaining segments
    }
    else
    {
        return std::vector<uint8_t>{};
    }
}

