/**
 * @brief   Constructs the second event payload with log data set in chronological order.
 * @details Assembles EventDataType 002 by embedding the EventDataType_LogData_Header_Identifier,
 *          the eventDataFrameCounter_ (serialized as four little-endian bytes), and the raw
 *          logData bytes in chronological order. The assembled buffer is submitted to
 *          SegmentPayloadIfExceedsMaxSize. The first (or only) segment is returned to the caller.
 *          If logData is empty, a header-only payload is constructed and the condition is logged.
 *          If segmentation produces no output, an empty vector is returned.
 * @param[in] logData  Serialized log data organized chronologically from oldest to newest
 *                     1-second block. Valid range: non-empty byte vector. An empty vector
 *                     results in a header-only payload.
 * @return  std::vector<uint8_t> — first segment of the assembled EventDataType 002 payload,
 *          or an empty vector if segmentation produced no output.
 * @retval  non-empty  First segment of the assembled and segmented log data payload.
 * @retval  empty      SegmentPayloadIfExceedsMaxSize returned no segments (fault condition).
 * @pre     eventDataFrameCounter_ is set to the current frame counter value.
 * @post    No state change beyond segmentNumber_ and totalSegments_ updated by segmentation.
 * @throws  None.
 * @note    Called by: ProbeComm. Call condition: Event_Trigger.
 * @warning If logData is empty, the payload contains only the header fields.
 *          Zero-fill handling for missing pre-trigger history is the responsibility of the
 *          pre-transmission log assembly layer.
 * @requirements SWR-REQ-03-07-004;SWR-REQ-03-07-006
 * @see     SegmentPayloadIfExceedsMaxSize, FillHeaderEventDataType002
 */
std::vector<uint8_t> ProbeComm::BuildPayloadLogDataSet(
    std::vector<uint8_t> logData) const noexcept
{
    // Step 1: Initialize local assembly buffer
    std::vector<uint8_t> assembledPayload;

    // Step 2: Append EventDataType 002 header identifier
    assembledPayload.push_back(EventDataType_LogData_Header_Identifier);

    // Step 3: Embed current eventDataFrameCounter (uint32_t) into header as little-endian bytes
    assembledPayload.push_back(static_cast<uint8_t>(eventDataFrameCounter_ & 0xFFU));
    assembledPayload.push_back(static_cast<uint8_t>((eventDataFrameCounter_ >> 8U) & 0xFFU));
    assembledPayload.push_back(static_cast<uint8_t>((eventDataFrameCounter_ >> 16U) & 0xFFU));
    assembledPayload.push_back(static_cast<uint8_t>((eventDataFrameCounter_ >> 24U) & 0xFFU));

    // Step 4: Validate logData input
    if (logData.empty())
    {
        // Log condition; proceed with header-only payload
        std::cerr << "[ProbeComm] BuildPayloadLogDataSet: logData is empty; constructing header-only payload.\n";
        // Zero-fill handling is the responsibility of the pre-transmission log assembly layer
    }
    else
    {
        // Step 5: Append chronologically ordered log data blocks
        assembledPayload.insert(assembledPayload.end(), logData.begin(), logData.end());
    }

    // Step 6: Invoke segmentation
    // DEVIATION: const_cast required because SegmentPayloadIfExceedsMaxSize is non-const per header.
    // RATIONALE: Pseudocode mandates the call; segmentation state is internal bookkeeping only.
    ProbeComm* mutableThis = const_cast<ProbeComm*>(this);
    std::vector<std::vector<uint8_t>> segmentedOutput =
        mutableThis->SegmentPayloadIfExceedsMaxSize(assembledPayload);

    // Step 7: Return first segment; caller handles full segment iteration
    if (!segmentedOutput.empty())
    {
        return segmentedOutput[0];
    }
    else
    {
        return std::vector<uint8_t>{};
    }
}

